namespace sv_4fa14ea3d251402e946b2df36f43fec4.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public DateTime Timestamp { get; set; }
    public string? Location { get; set; }
}

using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Models;

namespace sv_4fa14ea3d251402e946b2df36f43fec4.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Models;

namespace sv_4fa14ea3d251402e946b2df36f43fec4.Client.Services;

public class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Models;
using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Services;

namespace sv_4fa14ea3d251402e946b2df36f43fec4.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 2, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 20, 9, 0, 0, DateTimeKind.Utc), Location = "New York, NY" },
                new StatusUpdate { Description = "Departed facility", Timestamp = new DateTime(2026, 5, 21, 6, 30, 0, DateTimeKind.Utc), Location = "New York, NY" },
                new StatusUpdate { Description = "Arrived at sorting center", Timestamp = new DateTime(2026, 5, 23, 14, 15, 0, DateTimeKind.Utc), Location = "Chicago, IL" },
            ]
        },
        ["TRK-1002"] = new Shipment
        {
            TrackingNumber = "TRK-1002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 24, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 18, 10, 0, 0, DateTimeKind.Utc), Location = "Seattle, WA" },
                new StatusUpdate { Description = "In transit", Timestamp = new DateTime(2026, 5, 20, 8, 0, 0, DateTimeKind.Utc), Location = "Portland, OR" },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTime(2026, 5, 24, 7, 0, 0, DateTimeKind.Utc), Location = "San Francisco, CA" },
                new StatusUpdate { Description = "Delivered", Timestamp = new DateTime(2026, 5, 24, 11, 45, 0, DateTimeKind.Utc), Location = "San Francisco, CA" },
            ]
        },
        ["TRK-1003"] = new Shipment
        {
            TrackingNumber = "TRK-1003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Timestamp = new DateTime(2026, 5, 25, 16, 0, 0, DateTimeKind.Utc), Location = "Dallas, TX" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Models
@using sv_4fa14ea3d251402e946b2df36f43fec4.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<TrackShipment> Logger
@implements IDisposable

<PageTitle>Track Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment details for <strong>@TrackingNumber</strong>…
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else
{
    <h3>Shipment @_shipment.TrackingNumber</h3>

    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Current Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">
            @(_shipment.EstimatedDelivery?.ToString("f") ?? "—")
        </dd>
    </dl>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h4>Status History</h4>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Description</th>
                    <th>Location</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                        <td>@(update.Location ?? "—")</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
            return;

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        CancelPending();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        var cts = new CancellationTokenSource();
        _cts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Load was intentionally cancelled (navigation or disposal) — nothing to show.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

